        border-bottom-width: 2px; border-bottom-style: solid;
    }
    .amacx-product-page-content .summary-column ul { list-style-position: inside; padding: 0; margin: 0; }
    .amacx-product-page-content .summary-column li { line-height: 1.6; margin-bottom: 0.75rem; }
